class _MemeArenaAppState extends State<MemeArenaApp>{late final store=SessionStore(const FlutterSecureStorage());late final config=ApiConfig();late final repo=ApiRepository(createDio(config,sessionStore:store,onUnauthorized:()=>setState(()=>userId=null)),store);String? userId;bool loading=true;@override void initState(){super.initState();() async {await store.migrateLegacyIfNeeded(); final v=await store.userId(); if(mounted)setState((){userId=v;loading=false;});}();}void signedIn(String id)=>setState(()=>userId=id);Future<void> logout()async{try{await repo.logout();}catch(_){await store.clearUserSession();}setState(()=>userId=null);} @override Widget build(BuildContext context)=>MaterialApp(title:'Meme Arena',debugShowCheckedModeBanner:false,theme:darkTheme,home:loading?const Scaffold(body:Center(child:CircularProgressIndicator())):userId==null?Onboarding(repo:repo,store:store,onDone:signedIn):Home(repo:repo,store:store,config:config,onLogout:logout));}
class Onboarding extends StatefulWidget{const Onboarding({super.key,required this.repo,required this.store,required this.onDone});final ApiRepository repo;final SessionStore store;final ValueChanged<String> onDone;@override State<Onboarding> createState()=>_OnboardingState();}class _OnboardingState extends State<Onboarding>{final c=TextEditingController();String? err;bool busy=false;@override Widget build(BuildContext context)=>Scaffold(body:SafeArea(child:Center(child:SingleChildScrollView(padding:const EdgeInsets.all(24),child:Column(children:[Text('Meme Arena',style:Theme.of(context).textTheme.displaySmall),const SizedBox(height:24),TextField(controller:c,decoration:InputDecoration(labelText:'Nickname',errorText:err,border:const OutlineInputBorder())),const SizedBox(height:16),FilledButton(onPressed:busy?null:()async{final e=validateNickname(c.text);setState(()=>err=e);if(e!=null)return;setState(()=>busy=true);try{final u=await widget.repo.createGuest(c.text.trim());widget.onDone(u.id);}catch(ex){setState(()=>err=ex.toString());}finally{if(mounted)setState(()=>busy=false);}},child:Text(busy?'Загрузка...':'Начать'))]))));}
