class BattleScreen extends StatefulWidget{const BattleScreen({super.key,required this.repo,required this.config});final ApiRepository repo;final ApiConfig config;@override State<BattleScreen> createState()=>_BattleScreenState();}class _BattleScreenState extends State<BattleScreen>{Battle? b;String? error;bool loading=true;@override void initState(){super.initState();load();}Future<void> load()async{setState((){loading=true;error=null;});try{b=await widget.repo.getNextBattle();}catch(e){error=e.toString();}setState(()=>loading=false);}Future<void> vote(String id)async{await widget.repo.submitVote(b!,id);if(mounted)ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('Голос учтён')));load();}@override Widget build(c)=>SafeArea(child:loading?const Center(child:CircularProgressIndicator()):error!=null?Center(child:Text('Ошибка: $error')):b==null?const Center(child:Text('Пока нет доступных пар')):ListView(padding:const EdgeInsets.all(16),children:[Text('Какой мем смешнее?',style:Theme.of(c).textTheme.headlineMedium,textAlign:TextAlign.center),MemeCard(m:b!.left,config:widget.config,onTap:()=>vote(b!.left.id)),const Center(child:Text('VS')),MemeCard(m:b!.right,config:widget.config,onTap:()=>vote(b!.right.id))]));}
