class TopScreen extends StatefulWidget{const TopScreen({super.key,required this.repo,required this.config});final ApiRepository repo;final ApiConfig config;@override State<TopScreen> createState()=>_TopScreenState();}class _TopScreenState extends State<TopScreen>{late Future<List<MemeItem>> f;@override void initState(){super.initState();f=widget.repo.getTop();}@override Widget build(c)=>SafeArea(child:RefreshIndicator(onRefresh:()async=>setState(()=>f=widget.repo.getTop()),child:FutureBuilder<List<MemeItem>>(future:f,builder:(c,s){if(s.connectionState!=ConnectionState.done)return const Center(child:CircularProgressIndicator());if(s.hasError)return ListView(children:[Center(child:Padding(padding:EdgeInsets.all(24),child:Text('Ошибка: ${s.error}')))]);final items=s.data??[];if(items.isEmpty)return ListView(children:const [Center(child:Padding(padding:EdgeInsets.all(24),child:Text('Топ пока пуст')))]);return ListView.builder(itemCount:items.length,itemBuilder:(c,i){final m=items[i];return ListTile(leading:Text('${m.position??i+1}'),title:Text(m.title),subtitle:Text('Рейтинг ${m.rating} · ${m.wins}/${m.losses}/${m.battlesCount}'));});}))));}
